// W_Abort — Prep Signature. Assembles everything the Crypto (HMAC) node and the verifier need
// to authenticate a Slack interactivity POST before we act on it.
//
// Slack signs each request: signature = 'v0=' + HMAC_SHA256(signing_secret, `v0:{ts}:{raw_body}`).
// We must hash the EXACT raw body bytes, so the Slack Actions Webhook node has "Raw Body" enabled
// (the body arrives as binary). Headers carry the signature and timestamp; the signing secret
// comes from the config sheet (slack_signing_secret).
//
// Reads:
//   $('Read Config').all()            — slack_signing_secret
//   $('Slack Actions Webhook').first()— headers + raw binary body
// Emits one item: { base, secret, given_sig, ts, payload } → HMAC node → Verify & Parse Action.
const cfg = {};
$('Read Config').all().forEach(i => { if (i.json && i.json.key) cfg[i.json.key] = i.json.value; });
const secret = (cfg.slack_signing_secret || '').toString();

const wh = $('Slack Actions Webhook').first() || {};
const headers = (wh.json && wh.json.headers) || {};
const given_sig = (headers['x-slack-signature'] || headers['X-Slack-Signature'] || '').toString();
const ts = (headers['x-slack-request-timestamp'] || headers['X-Slack-Request-Timestamp'] || '').toString();

// Raw body: prefer the exact bytes from the webhook's binary (Raw Body = ON). Fall back to a
// string body or a reconstructed form-encoding — the fallbacks won't match Slack's signature,
// so verification will (correctly) reject if Raw Body wasn't enabled.
let raw = '';
const b = wh.binary;
if (b && b.data && b.data.data) {
  raw = Buffer.from(b.data.data, 'base64').toString('utf8');
} else if (typeof (wh.json && wh.json.body) === 'string') {
  raw = wh.json.body;
} else if (wh.json && wh.json.body && wh.json.body.payload) {
  raw = 'payload=' + encodeURIComponent(wh.json.body.payload);
}

// Extract the `payload` field from the form-encoded raw body. We parse it by hand
// (regex + decodeURIComponent) rather than URLSearchParams — the latter is unreliable in
// the n8n Code-node sandbox and silently yielded '' even though the raw body is intact
// (the HMAC over `base` still matches, proving raw is correct). '+' → space per form rules.
let payload = '';
const m = raw.match(/(?:^|&)payload=([^&]*)/);
if (m) {
  try { payload = decodeURIComponent(m[1].replace(/\+/g, ' ')); }
  catch (e) { payload = m[1]; }
}

return [{ json: { base: `v0:${ts}:${raw}`, secret, given_sig, ts, payload } }];

// W_Abort — Verify & Parse Action. Authenticates the Slack request, then extracts the stop intent.
// This is the security gate for an otherwise public POST webhook: if anything fails to verify we
// return [] (no abort is written, no Slack posted). Only a genuine, fresh, correctly-signed
// "abort_localization" button click gets through.
//
// Reads:
//   $('Prep Signature').first().json — base, secret, given_sig, ts, payload
//   $json.computed_sig               — hex HMAC produced by the Crypto (HMAC) node
// Emits one item { run_token, slack_user, response_url } on success; [] on any rejection.
const prep = $('Prep Signature').first().json || {};
const computed = ($json.computed_sig || '').toString();
const given = (prep.given_sig || '').toString();
const tsNum = Number(prep.ts);
const now = Math.floor(Date.now() / 1000);

if (!prep.secret) { console.warn('W_Abort: slack_signing_secret missing from config — rejecting'); return []; }
if (!given || !computed) { console.warn('W_Abort: missing signature/hash — rejecting'); return []; }
if (!tsNum || Math.abs(now - tsNum) > 300) { console.warn('W_Abort: stale or invalid timestamp — rejecting (replay guard)'); return []; }

const expected = 'v0=' + computed;
if (expected.length !== given.length || expected !== given) {
  console.warn('W_Abort: Slack signature mismatch — rejecting');
  return [];
}

let payload;
try { payload = JSON.parse(prep.payload); } catch (e) { console.warn('W_Abort: could not parse interaction payload — rejecting'); return []; }

const action = (payload.actions && payload.actions[0]) || {};
if (action.action_id !== 'abort_localization') { console.log('W_Abort: ignoring non-abort action_id', action.action_id); return []; }

const runToken = (action.value || '').toString();
if (!runToken) { console.warn('W_Abort: stop button carried no run_token — rejecting'); return []; }

const user = (payload.user && (payload.user.username || payload.user.name || payload.user.id)) || 'unknown';
const responseUrl = (payload.response_url || '').toString();

console.log(`W_Abort: verified stop request for run ${runToken} by ${user}`);
return [{ json: { run_token: runToken, slack_user: user, response_url: responseUrl } }];

// W_Abort — Prepare Abort Row. Turns the verified stop request into the single config row the
// following Sheets appendOrUpdate writes: localization_abort_token = run_token. A checkpoint
// halts the run only when localization_abort_token === localization_run_token.
const v = $('Verify & Parse Action').first().json || {};
const runToken = (v.run_token || '').toString();
return [{ json: { key: 'localization_abort_token', value: runToken } }];

// W_Abort — Build Confirm Slack. Posts a plain-text confirmation back to the channel so the team
// sees the stop was registered and understands when it takes effect. Emits { channel, text } for
// the native Slack node (same idiom as W_Master / W_Regen completion messages).
const cfg = {};
$('Read Config').all().forEach(i => { if (i.json && i.json.key) cfg[i.json.key] = i.json.value; });
const channel = cfg.slack_channel;
if (!channel) { console.log('W_Abort: slack_channel missing — skipping confirmation'); return []; }

const v = $('Verify & Parse Action').first().json || {};
const lines = [
  ':octagonal_sign: *Localization stopped*',
  '',
  `*Initiated by:* ${v.slack_user || 'unknown'}`,
  'The current language will finish. No new languages will start. Active processes run to completion.',
  '',
  ':hourglass_flowing_sand: Awaiting confirmation in the next message.',
];
return [{ json: { channel, text: lines.join('\n') } }];
